module Xberg
  # Async lifecycle status for an enrichment job.
  #
  # Intended for use with any polling or event-driven pipeline that needs
  # to track whether enrichment has completed, succeeded, or failed.
  #
  # # Serialisation
  #
  # Uses an internally-tagged `"status"` field with `snake_case` variants:
  #
  # ```json
  # { "status": "pending" }
  # { "status": "completed", "result": { ... } }
  # { "status": "failed", "error": "text too large" }
  # ```
  #
  #
  # ```
  # use xberg::enrichment::{EnrichStatus, EnrichResult};
  #
  # let s = EnrichStatus::Pending;
  # let json = serde_json::to_value(&s).unwrap();
  # assert_eq!(json["status"], "pending");
  #
  # let s = EnrichStatus::Completed { result: EnrichResult::default() };
  # let json = serde_json::to_value(&s).unwrap();
  # assert_eq!(json["status"], "completed");
  # ```
  module EnrichStatus
    extend T::Helpers
    extend T::Sig

    interface!

    # Dispatch from a Hash to the appropriate variant constructor.
    # @param hash [Hash] with discriminator field and variant-specific fields
    # @return [variant_class] an instance of the appropriate variant
    sig { params(hash: T::Hash[T.untyped, T.untyped]).returns(T.untyped) }
    def self.from_hash(hash)
      discriminator = hash[:status] || hash["status"]
      case discriminator
      when "pending" then EnrichStatusPending.from_hash(hash)
      when "completed" then EnrichStatusCompleted.from_hash(hash)
      when "failed" then EnrichStatusFailed.from_hash(hash)
      else raise "Unknown discriminator: #{discriminator}"
      end
    end
  end
